Problèmes identifiés :
1) La relation `@OneToOne` n'est pas complète : il manque le côté inverse et le décorateur `@JoinColumn()` (le côté propriétaire).
2) `visitorId` et `user` sont tous deux présents alors qu'un panier ne devrait avoir qu'un seul des deux (soit un utilisateur connecté, soit un anonyme).
3) Il manque les relations inverses du côté de `CartItem` et `User`.

Version corrigée :
```typescript
@Entity()
export class Cart {
  @PrimaryGeneratedColumn()
  id: number;

  @OneToOne(() => User, (user) => user.cart, { nullable: true })
  @JoinColumn()
  user?: User;

  @Column({ nullable: true })
  visitorId?: string;

  @OneToMany(() => CartItem, (cartItem) => cartItem.cart, { cascade: true })
  items: CartItem[];

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}
```

```typescript
async function mergeCarts(visitorId: string, userId: number): Promise<Cart> {
  // 1. Récupérer le panier anonyme
  const anonymousCart = await cartRepository.findOne({
    where: { visitorId },
    relations: ['items', 'items.product']
  });

  // 2. Récupérer le panier de l'utilisateur (ou en créer un)
  let userCart = await cartRepository.findOne({
    where: { user: { id: userId } },
    relations: ['items', 'items.product']
  });

  if (!userCart) {
    userCart = cartRepository.create({ user: { id: userId }, items: [] });
    await cartRepository.save(userCart);
  }

  // 3. Si pas de panier anonyme, retourner le panier utilisateur
  if (!anonymousCart || anonymousCart.items.length === 0) {
    return userCart;
  }

  // 4. Fusionner les items : addition des quantités pour les produits identiques
  for (const anonymousItem of anonymousCart.items) {
    const existingItem = userCart.items.find(
      item => item.productId === anonymousItem.productId &&
              item.variationId === anonymousItem.variationId
    );

    if (existingItem) {
      existingItem.quantity += anonymousItem.quantity;
      await cartItemRepository.save(existingItem);
    } else {
      // Créer un nouvel item dans le panier utilisateur
      const newItem = cartItemRepository.create({
        cart: userCart,
        productId: anonymousItem.productId,
        quantity: anonymousItem.quantity,
        variationId: anonymousItem.variationId,
        price: anonymousItem.price
      });
      userCart.items.push(newItem);
      await cartItemRepository.save(newItem);
    }
  }

  // 5. Supprimer le panier anonyme (cascade supprimera les items)
  await cartRepository.remove(anonymousCart);

  // 6. Retourner le panier utilisateur mis à jour
  return userCart;
}
```

Plusieurs approches possibles :

1) **Cron job** : exécuter une tâche planifiée chaque nuit qui supprime les paniers dont `updatedAt < NOW() - INTERVAL 7 DAYS` et `visitorId IS NOT NULL AND userId IS NULL`.

2) **Trigger PostgreSQL** : créer un trigger qui vérifie l'âge du panier avant toute lecture/écriture.

3) **Middleware/Interceptor** : à chaque requête sur le panier, vérifier si l'utilisateur est anonyme et si son panier a expiré ; si oui, créer un nouveau panier.

**Implémentation avec cron dans NestJS :**
```typescript
@Injectable()
export class CartCleanupService {
  @Cron('0 2 * * *') // Tous les jours à 2h du matin
  async deleteExpiredCarts() {
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

    await cartRepository
      .createQueryBuilder()
      .delete()
      .where('visitorId IS NOT NULL')
      .andWhere('userId IS NULL')
      .andWhere('updatedAt < :date', { date: sevenDaysAgo })
      .execute();
  }
}
```

```typescript
// DTO
export class AddToCartDto {
  @IsNumber()
  productId: number;

  @IsNumber()
  @Min(1)
  quantity: number;

  @IsOptional()
  @IsString()
  visitorId?: string;

  @IsOptional()
  variationId?: number;
}

// Service
@Injectable()
export class CartService {
  async addToCart(addToCartDto: AddToCartDto, userId?: number): Promise<Cart> {
    let cart: Cart;

    // 1. Trouver ou créer le panier
    if (userId) {
      cart = await this.findOrCreateCartByUser(userId);
    } else if (addToCartDto.visitorId) {
      cart = await this.findOrCreateCartByVisitor(addToCartDto.visitorId);
    } else {
      throw new BadRequestException('userId ou visitorId requis');
    }

    // 2. Vérifier le produit et le stock
    const product = await this.productService.findOne(addToCartDto.productId);
    if (!product) {
      throw new NotFoundException('Produit non trouvé');
    }

    const requestedStock = addToCartDto.quantity;
    if (product.stock < requestedStock) {
      throw new BadRequestException(`Stock insuffisant. Disponible: ${product.stock}`);
    }

    // 3. Vérifier si le produit est déjà dans le panier
    const existingItem = cart.items.find(
      item => item.productId === addToCartDto.productId &&
              item.variationId === addToCartDto.variationId
    );

    if (existingItem) {
      const newQuantity = existingItem.quantity + addToCartDto.quantity;
      if (product.stock < newQuantity) {
        throw new BadRequestException(`Quantité totale (${newQuantity}) dépasse le stock (${product.stock})`);
      }
      existingItem.quantity = newQuantity;
      await this.cartItemRepository.save(existingItem);
    } else {
      const newItem = this.cartItemRepository.create({
        cart,
        productId: addToCartDto.productId,
        quantity: addToCartDto.quantity,
        variationId: addToCartDto.variationId,
        price: product.price
      });
      cart.items.push(newItem);
      await this.cartItemRepository.save(newItem);
    }

    // 4. Mettre à jour la date du panier
    cart.updatedAt = new Date();
    await this.cartRepository.save(cart);

    return cart;
  }

  private async findOrCreateCartByUser(userId: number): Promise<Cart> {
    let cart = await this.cartRepository.findOne({
      where: { user: { id: userId } },
      relations: ['items']
    });
    if (!cart) {
      cart = this.cartRepository.create({ user: { id: userId }, items: [] });
      await this.cartRepository.save(cart);
    }
    return cart;
  }

  private async findOrCreateCartByVisitor(visitorId: string): Promise<Cart> {
    let cart = await this.cartRepository.findOne({
      where: { visitorId },
      relations: ['items']
    });
    if (!cart) {
      cart = this.cartRepository.create({ visitorId, items: [] });
      await this.cartRepository.save(cart);
    }
    return cart;
  }
}

// Controller
@Controller('cart')
@UseGuards(JwtAuthGuardOptional) // Guard optionnel
 export class CartController {
  @Post('add')
  async addToCart(
    @Body() addToCartDto: AddToCartDto,
    @CurrentUser() user?: User
  ) {
    return this.cartService.addToCart(addToCartDto, user?.id);
  }
}
```
